-- Limpar dados existentes (exceto o curso de teste)
DELETE FROM lessons WHERE module_id IN (SELECT id FROM modules WHERE course_id > 1);
DELETE FROM modules WHERE course_id > 1;
DELETE FROM courses WHERE id > 1;

-- Curso 1: Trilha Iniciante
INSERT INTO courses (title, description, difficulty, duration, `order`, is_published) VALUES
('Trilha Iniciante', 'Fundamentos de programação e ferramentas essenciais para começar sua jornada como desenvolvedor', 'beginner', 480, 1, 1);

SET @course1_id = LAST_INSERT_ID();

INSERT INTO modules (course_id, title, description, `order`) VALUES
(@course1_id, 'Introdução à Programação', 'Conceitos básicos de lógica de programação e algoritmos', 1),
(@course1_id, 'Git e Controle de Versão', 'Aprenda a usar Git para gerenciar seu código', 2),
(@course1_id, 'HTML e CSS Básico', 'Crie suas primeiras páginas web', 3);

SET @module1_1 = LAST_INSERT_ID() - 2;
SET @module1_2 = LAST_INSERT_ID() - 1;
SET @module1_3 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content, duration, `order`) VALUES
(@module1_1, 'O que é Programação?', '# O que é Programação?\n\nProgramação é o processo de criar instruções que um computador pode executar. Nesta aula, você aprenderá os conceitos fundamentais.', 30, 1),
(@module1_1, 'Variáveis e Tipos de Dados', '# Variáveis e Tipos de Dados\n\nVariáveis são espaços na memória para armazenar informações. Aprenda sobre strings, números, booleanos e mais.', 45, 2),
(@module1_1, 'Estruturas de Controle', '# Estruturas de Controle\n\nConheça if/else, switch e loops (for, while) para controlar o fluxo do seu programa.', 50, 3),
(@module1_2, 'Introdução ao Git', '# Introdução ao Git\n\nGit é um sistema de controle de versão distribuído. Aprenda os comandos básicos: init, add, commit, push, pull.', 40, 1),
(@module1_2, 'Branches e Merge', '# Branches e Merge\n\nTrabalhe com branches para desenvolver features isoladamente e aprenda a fazer merge de código.', 45, 2),
(@module1_2, 'GitHub e Colaboração', '# GitHub e Colaboração\n\nUse GitHub para hospedar seus repositórios e colaborar com outros desenvolvedores através de Pull Requests.', 35, 3),
(@module1_3, 'Estrutura HTML', '# Estrutura HTML\n\nAprenda as tags fundamentais: html, head, body, div, p, h1-h6, a, img e mais.', 40, 1),
(@module1_3, 'Estilização com CSS', '# Estilização com CSS\n\nAprenda seletores, propriedades de cor, fonte, espaçamento e posicionamento.', 50, 2),
(@module1_3, 'Flexbox e Grid', '# Flexbox e Grid\n\nDomine layouts modernos com Flexbox e CSS Grid para criar interfaces responsivas.', 55, 3);

-- Curso 2: Trilha Intermediária
INSERT INTO courses (title, description, difficulty, duration, `order`, is_published) VALUES
('Trilha Intermediária', 'Desenvolvimento web moderno e bancos de dados relacionais', 'intermediate', 720, 2, 1);

SET @course2_id = LAST_INSERT_ID();

INSERT INTO modules (course_id, title, description, `order`) VALUES
(@course2_id, 'JavaScript Moderno', 'ES6+, async/await e manipulação do DOM', 1),
(@course2_id, 'React Fundamentos', 'Componentes, hooks e gerenciamento de estado', 2),
(@course2_id, 'Bancos de Dados SQL', 'MySQL, queries e modelagem de dados', 3);

SET @module2_1 = LAST_INSERT_ID() - 2;
SET @module2_2 = LAST_INSERT_ID() - 1;
SET @module2_3 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content, duration, `order`) VALUES
(@module2_1, 'Arrow Functions e Destructuring', '# JavaScript ES6+\n\nAprenda arrow functions, destructuring, spread operator e template literals.', 45, 1),
(@module2_1, 'Promises e Async/Await', '# Programação Assíncrona\n\nEntenda callbacks, promises e async/await para trabalhar com operações assíncronas.', 50, 2),
(@module2_1, 'Manipulação do DOM', '# Manipulação do DOM\n\nAprenda a selecionar elementos, modificar conteúdo e adicionar event listeners.', 40, 3),
(@module2_2, 'Componentes e Props', '# Componentes React\n\nCrie componentes funcionais e aprenda a passar dados através de props.', 50, 1),
(@module2_2, 'Hooks: useState e useEffect', '# React Hooks\n\nGerencie estado com useState e efeitos colaterais com useEffect.', 55, 2),
(@module2_2, 'Context API e useContext', '# Gerenciamento de Estado Global\n\nCompartilhe estado entre componentes usando Context API.', 45, 3),
(@module2_3, 'Introdução a Bancos de Dados', '# Bancos de Dados Relacionais\n\nConceitos de tabelas, colunas, linhas, chaves primárias e estrangeiras.', 40, 1),
(@module2_3, 'Queries SQL Básicas', '# SQL Básico\n\nAprenda SELECT, INSERT, UPDATE, DELETE e WHERE para manipular dados.', 50, 2),
(@module2_3, 'JOINs e Relacionamentos', '# Relacionamentos entre Tabelas\n\nUse INNER JOIN, LEFT JOIN e RIGHT JOIN para combinar dados de múltiplas tabelas.', 55, 3);

-- Curso 3: Trilha Avançada
INSERT INTO courses (title, description, difficulty, duration, `order`, is_published) VALUES
('Trilha Avançada', 'Arquitetura de software, DevOps e práticas avançadas de desenvolvimento', 'advanced', 960, 3, 1);

SET @course3_id = LAST_INSERT_ID();

INSERT INTO modules (course_id, title, description, `order`) VALUES
(@course3_id, 'Arquitetura de Software', 'Design patterns e princípios SOLID', 1),
(@course3_id, 'Docker e Containers', 'Containerização de aplicações', 2),
(@course3_id, 'CI/CD e DevOps', 'Automação de deploy e integração contínua', 3);

SET @module3_1 = LAST_INSERT_ID() - 2;
SET @module3_2 = LAST_INSERT_ID() - 1;
SET @module3_3 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content, duration, `order`) VALUES
(@module3_1, 'Princípios SOLID', '# Princípios SOLID\n\nAprenda Single Responsibility, Open/Closed, Liskov Substitution, Interface Segregation e Dependency Inversion.', 60, 1),
(@module3_1, 'Design Patterns Criacionais', '# Patterns Criacionais\n\nSingleton, Factory, Builder e Prototype para criação de objetos.', 55, 2),
(@module3_1, 'Design Patterns Estruturais', '# Patterns Estruturais\n\nAdapter, Decorator, Facade e Proxy para organizar estruturas de código.', 50, 3),
(@module3_2, 'Introdução ao Docker', '# Docker Básico\n\nConceitos de images, containers, volumes e networks.', 45, 1),
(@module3_2, 'Dockerfile e Docker Compose', '# Criando Containers\n\nEscreva Dockerfiles e orquestre múltiplos containers com Docker Compose.', 55, 2),
(@module3_2, 'Deploy com Docker', '# Deploy de Aplicações\n\nPublique suas aplicações em produção usando Docker e registries.', 50, 3),
(@module3_3, 'Integração Contínua', '# CI - Continuous Integration\n\nAutomatize testes e builds com GitHub Actions, GitLab CI ou Jenkins.', 50, 1),
(@module3_3, 'Deploy Contínuo', '# CD - Continuous Deployment\n\nAutomatize deploys para staging e produção com pipelines.', 55, 2),
(@module3_3, 'Monitoramento e Logs', '# Observabilidade\n\nMonitore aplicações em produção com logs, métricas e alertas.', 45, 3);

